import{_ as t,o as a,c as e,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"All Cost Data Moving to ROI Hub","description":"","frontmatter":{"title":"All Cost Data Moving to ROI Hub","slug":"all-cost-data-moving-to-roi-hub"},"headers":[],"relativePath":"account-hub/all-cost-data-moving-to-roi-hub.md","filePath":"account-hub/all-cost-data-moving-to-roi-hub.md"}'),i={name:"account-hub/all-cost-data-moving-to-roi-hub.md"};function r(s,o,l,c,d,u){return a(),e("div",null,[...o[0]||(o[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch is transitioning all self-attributing network (SAN) cost data to ROI Hub. This change affects cost data from Facebook, Google Ads, Snap, TikTok, and Apple Ads. Cost data from these SANs will no longer be automatically imported and displayed in analytics and exports through legacy systems.</p><p>Additionally, Branch’s existing Cost on Links solution is being deprecated in favor of ROI Hub. These changes align with Branch&#39;s goal of streamlining our products while providing customers with unified cost data and revenue insights, an improved user experience with intuitive design, and better visibility into ad partner connections.</p><h2 id="san-cost-data-moving-to-roi-hub" tabindex="-1">SAN cost data moving to ROI Hub <a class="header-anchor" href="#san-cost-data-moving-to-roi-hub" aria-label="Permalink to &quot;SAN cost data moving to ROI Hub&quot;">​</a></h2><p><strong>Current behavior</strong>: Cost data from SANs is automatically imported when these networks are authenticated, then displayed in analytics and exports.</p><p><strong>Upcoming change</strong>: SAN cost data will only be available through <a href="./roi-hub.html">ROI Hub</a> as part of <a href="https://help.branch.io/v1/docs/packaging#performance-pro-tier" target="_blank" rel="noreferrer">Performance Pro</a>. Legacy customers will need to purchase ROI Hub to continue accessing this data.</p><h4 id="affected-ad-networks" tabindex="-1">Affected ad networks <a class="header-anchor" href="#affected-ad-networks" aria-label="Permalink to &quot;Affected ad networks&quot;">​</a></h4><ul><li>Facebook</li><li>Google Ads</li><li>Snap</li><li>TikTok</li><li>Apple Ads</li></ul><h2 id="cost-on-links-to-be-discontinued" tabindex="-1">Cost on Links to be discontinued <a class="header-anchor" href="#cost-on-links-to-be-discontinued" aria-label="Permalink to &quot;Cost on Links to be discontinued&quot;">​</a></h2><p><strong>Current behavior:</strong> The Cost on Links solution allows customers to configure cost data via parameters on Branch Links, with ad networks populating cost values that Branch aggregates.</p><p><strong>Upcoming change:</strong> The Cost on Links solution will be deprecated and also replaced by ROI Hub.</p><h2 id="more-information" tabindex="-1">More information <a class="header-anchor" href="#more-information" aria-label="Permalink to &quot;More information&quot;">​</a></h2><p>These changes support Branch’s goal of consolidating our infrastructure and making valuable insights easy for customers to find.</p><p>They also come with all the additional benefits of ROI Hub, which include:</p><ul><li><strong>Increased value:</strong> ROI Hub unifies your cost data and revenue insights, and helps you understand the actual impact of your ad dollars.</li><li><strong>Improved user experience:</strong> The Cost on Links feature has complex implementation requirements, whereas ROI Hub boasts an intuitive, modern design.</li><li><strong>Better visibility:</strong> ROI Hub makes it easy to monitor the status of each of your ad partner connections, so you can find and fix issues quickly.</li></ul><p>You can find <strong>ROI Hub</strong> in the Branch Dashboard under <strong>Ads</strong>, or access it directly <a href="https://monster-factory-web.app.link/e/release-note-to-roi-hub-april-2025" target="_blank" rel="noreferrer">here</a>.</p><p>For questions or concerns about these changes, please reach out to your Branch point of contact.</p>',17)])])}const g=t(i,[["render",r]]);export{p as __pageData,g as default};
